  const prev = products[idx];
  const now2 = (/* @__PURE__ */ new Date()).toISOString();
  const skipFields = /* @__PURE__ */ new Set(["changeHistory", "createdAt", "id"]);
  const newEntries = Object.entries(changes).filter(([f]) => !skipFields.has(f)).filter(
    ([f, v2]) => String(prev[f] ?? "") !== String(v2 ?? "")
  ).map(([f, v2]) => ({
    timestamp: now2,
    field: f,
    oldValue: String(prev[f] ?? ""),
    newValue: String(v2 ?? ""),
    changedBy: user,
    action: "Update",
    reason: reason ?? ""
  }));
  const updated = {
    ...prev,
    ...changes,
    id: prev.id,
    createdAt: prev.createdAt,
    createdBy: prev.createdBy,
    updatedAt: now2,
    changeHistory: [...prev.changeHistory, ...newEntries]
  };
